window.Pages=window.Pages||{},Pages.configuracion={render(e){const t=JSON.parse(localStorage.getItem("configuracion"))||{},n=t.uf_valor||"",a=t.porcentaje||0,r=t.uf_fecha||"";e.innerHTML=`\n      <div class="page-title"><h1>⚙️ Configuración</h1><p>Ajusta los parámetros de la fórmula de crédito.</p></div>\n      <div class="card">\n        <h3>📐 Fórmula de Cálculo — Límite Máx. Crédito</h3>\n        <div style="background:rgba(212,175,55,0.06);border:1px solid rgba(212,175,55,0.15);border-radius:10px;padding:16px;margin:16px 0;font-size:14px;color:#d1d5db;font-family:monospace;">\n          Límite = ((Sueldo × 60) ÷ UF) × (1 + Porcentaje ÷ 100)\n        </div>\n        <div class="form-row">\n          <div class="form-group">\n            <label>Valor actual de la UF ($)</label>\n            <div style="display:flex;gap:8px;">\n              <input type="number" id="cfg-uf" min="1" step="1" value="${n}" style="flex:1;">\n              <button class="btn btn-sm" id="cfg-btn-fetch" onclick="Pages.configuracion.fetchUF()" title="Obtener UF actual desde mindicador.cl">🔄</button>\n            </div>\n            <div id="cfg-uf-status" style="font-size:11px;color:#6b7280;margin-top:4px;">${r?`📅 Última actualización: ${r}`:"💡 Usa el botón 🔄 para obtener el valor actual desde mindicador.cl"}</div>\n          </div>\n          <div class="form-group">\n            <label>Porcentaje adicional (0 – 100)</label>\n            <input type="number" id="cfg-porcentaje" min="0" max="100" step="0.01" value="${a}">\n          </div>\n        </div>\n        <div id="cfg-preview" style="margin-top:12px;padding:12px;background:rgba(255,255,255,0.02);border-radius:8px;font-size:13px;color:#9ca3af;"></div>\n        <div style="margin-top:16px;">\n          <button class="btn btn-primary" onclick="Pages.configuracion.guardar()">💾 Guardar configuración</button>\n        </div>\n        <div id="cfg-resultado"></div>\n      </div>\n    `,this.actualizarPreview(),document.getElementById("cfg-uf").addEventListener("input",()=>this.actualizarPreview()),document.getElementById("cfg-porcentaje").addEventListener("input",()=>this.actualizarPreview()),n||this.fetchUF()},async fetchUF(){const e=document.getElementById("cfg-btn-fetch"),t=document.getElementById("cfg-uf-status");e&&(e.textContent="⏳"),t&&(t.textContent="Consultando mindicador.cl...");try{const e=await fetch("https://mindicador.cl/api/uf");if(!e.ok)throw new Error("Error al consultar la API");const n=await e.json(),a=n.serie?.[0]?.valor,r=n.serie?.[0]?.fecha;if(!a)throw new Error("No se encontró el valor UF");const o=document.getElementById("cfg-uf");o&&(o.value=Math.round(a)),t&&(t.textContent=`📅 Actualizado desde mindicador.cl — ${r||"hoy"}`),this.actualizarPreview()}catch(e){t&&(t.textContent=`❌ Error: ${e.message}. Ingresa el valor manualmente.`)}finally{e&&(e.textContent="🔄")}},actualizarPreview(){const e=+document.getElementById("cfg-uf")?.value||0,t=+document.getElementById("cfg-porcentaje")?.value||0,n=document.getElementById("cfg-preview");if(n)if(e>0){const a=(60*1e6/e*(1+t/100)).toFixed(2);n.innerHTML=`🔮 Vista previa con sueldo $1.000.000: <strong>((1.000.000 × 60) ÷ ${e.toLocaleString()}) × (1 + ${t}%) = ${a} UF</strong>`}else n.innerHTML="💡 Ingresa o consulta el valor UF para ver la vista previa."},guardar(){const e=+document.getElementById("cfg-uf").value,t=+document.getElementById("cfg-porcentaje").value;if(t<0||t>100)return void(document.getElementById("cfg-resultado").innerHTML='<div class="alert alert-error">El porcentaje debe estar entre 0 y 100.</div>');if(!e||e<=0)return void(document.getElementById("cfg-resultado").innerHTML='<div class="alert alert-error">Ingresa un valor UF válido.</div>');const n=document.getElementById("cfg-uf-status"),a=n?.textContent?.includes("Actualizado")?(new Date).toLocaleDateString("es-CL"):"";localStorage.setItem("configuracion",JSON.stringify({uf_valor:e,porcentaje:t,uf_fecha:a})),document.getElementById("cfg-resultado").innerHTML='<div class="alert alert-success">✅ Configuración guardada correctamente.</div>'}};